/** Represents an update of repository state. Note that empty commits are allowed, which include no repo data changes, but an update to rev and signature. */
typedef struct wf_lex_com_atproto_sync_subscribe_repos_commit {
    /** The stream sequence number of this message. */
    int64_t seq;
    /** DEPRECATED -- unused */
    bool rebase;
    /** DEPRECATED -- replaced by #sync event and data limits. Indicates that this commit contained too many ops, or data size was too large. Consumers will need to make a separate request to get missing data. */
    bool too_big;
    /** The repo this event comes from. Note that all other message types name this field 'did'. */
    const char * repo;
    /** Repo commit object CID. */
    wf_lex_cid_link commit;
    /** The rev of the emitted commit. Note that this information is also in the commit object included in blocks, unless this is a tooBig event. */
    const char * rev;
    /** The rev of the last emitted commit from this repo (if any). */
    const char * since;
    /** CAR file containing relevant blocks, as a diff since the previous repo state. The commit must be included as a block, and the commit block CID must be the first entry in the CAR header 'roots' list. */
    wf_lex_bytes blocks;
    WF_LEX_ARRAY(const wf_lex_com_atproto_sync_subscribe_repos_repo_op *) ops;
    WF_LEX_ARRAY(wf_lex_cid_link) blobs;
    /** The root CID of the MST tree for the previous commit from this repo (indicated by the 'since' revision field in this message). Corresponds to the 'data' field in the repo commit object. NOTE: this field is effectively required for the 'inductive' version of firehose. */
    bool has_prev_data;
    wf_lex_cid_link prev_data;
    /** Timestamp of when this message was originally broadcast. */
    const char * time;
} wf_lex_com_atproto_sync_subscribe_repos_commit;

/** Updates the repo to a new state, without necessarily including that state on the firehose. Used to recover from broken commit streams, data loss incidents, or in situations where upstream host does not know recent state of the repository. */
typedef struct wf_lex_com_atproto_sync_subscribe_repos_sync {
    /** The stream sequence number of this message. */
    int64_t seq;
    /** The account this repo event corresponds to. Must match that in the commit object. */
    const char * did;
    /** CAR file containing the commit, as a block. The CAR header must include the commit block CID as the first 'root'. */
    wf_lex_bytes blocks;
    /** The rev of the commit. This value must match that in the commit object. */
    const char * rev;
    /** Timestamp of when this message was originally broadcast. */
    const char * time;
} wf_lex_com_atproto_sync_subscribe_repos_sync;

/** Represents a change to an account's identity. Could be an updated handle, signing key, or pds hosting endpoint. Serves as a prod to all downstream services to refresh their identity cache. */
typedef struct wf_lex_com_atproto_sync_subscribe_repos_identity {
    int64_t seq;
    const char * did;
    const char * time;
    /** The current handle for the account, or 'handle.invalid' if validation fails. This field is optional, might have been validated or passed-through from an upstream source. Semantics and behaviors for PDS vs Relay may evolve in the future; see atproto specs for more details. */
    bool has_handle;
    const char * handle;
} wf_lex_com_atproto_sync_subscribe_repos_identity;

/** Represents a change to an account's status on a host (eg, PDS or Relay). The semantics of this event are that the status is at the host which emitted the event, not necessarily that at the currently active PDS. Eg, a Relay takedown would emit a takedown with active=false, even if the PDS is still active. */
typedef struct wf_lex_com_atproto_sync_subscribe_repos_account {
    int64_t seq;
    const char * did;
    const char * time;
    /** Indicates that the account has a repository which can be fetched from the host that emitted this event. */
    bool active;
    /** If active=false, this optional field indicates a reason for why the account is not active. */
    bool has_status;
    const char * status;
} wf_lex_com_atproto_sync_subscribe_repos_account;

typedef struct wf_lex_com_atproto_sync_subscribe_repos_info {
    const char * name;
    bool has_message;
    const char * message;
} wf_lex_com_atproto_sync_subscribe_repos_info;

/** A repo operation, ie a mutation of a single record. */
typedef struct wf_lex_com_atproto_sync_subscribe_repos_repo_op {
    const char * action;
    const char * path;
    /** For creates and updates, the new record CID. For deletions, null. */
    wf_lex_cid_link cid;
    /** For updates and deletes, the previous record CID (required for inductive firehose). For creations, field should not be defined. */
    bool has_prev;
    wf_lex_cid_link prev;
} wf_lex_com_atproto_sync_subscribe_repos_repo_op;

