/** Statistics about a particular account subject */
typedef struct wf_lex_tools_ozone_moderation_defs_account_stats {
    /** Total number of reports on the account */
    bool has_report_count;
    int64_t report_count;
    /** Total number of appeals against a moderation action on the account */
    bool has_appeal_count;
    int64_t appeal_count;
    /** Number of times the account was suspended */
    bool has_suspend_count;
    int64_t suspend_count;
    /** Number of times the account was escalated */
    bool has_escalate_count;
    int64_t escalate_count;
    /** Number of times the account was taken down */
    bool has_takedown_count;
    int64_t takedown_count;
} wf_lex_tools_ozone_moderation_defs_account_stats;

/** Statistics about a set of record subject items */
typedef struct wf_lex_tools_ozone_moderation_defs_records_stats {
    /** Cumulative sum of the number of reports on the items in the set */
    bool has_total_reports;
    int64_t total_reports;
    /** Number of items that were reported at least once */
    bool has_reported_count;
    int64_t reported_count;
    /** Number of items that were escalated at least once */
    bool has_escalated_count;
    int64_t escalated_count;
    /** Number of items that were appealed at least once */
    bool has_appealed_count;
    int64_t appealed_count;
    /** Total number of item in the set */
    bool has_subject_count;
    int64_t subject_count;
    /** Number of item currently in "reviewOpen" or "reviewEscalated" state */
    bool has_pending_count;
    int64_t pending_count;
    /** Number of item currently in "reviewNone" or "reviewClosed" state */
    bool has_processed_count;
    int64_t processed_count;
    /** Number of item currently taken down */
    bool has_takendown_count;
    int64_t takendown_count;
} wf_lex_tools_ozone_moderation_defs_records_stats;

/** Strike information for an account */
